import { useState } from "react";
import ScreenOne from "./Screenone/ScreenOne";
import ScreenTwo from "./Screentwo/ScreenTwo";
import ScreenThree from "./Screenthree/ScreenThree";
import ScreenFour from "./Screenfour/ScreenFour";
import ScreenFive from "./Screenfive/ScreenFive";
import ScreenSix from "./Screensix/ScreenSix";
import ScreenSeven from "./Screenseven/ScreenSeven";
import ProgressBar from "./ProgressBar";
import "./quiz.css";

const API_BASE_URL = 'https://e-nutritionist-b1d035f17120.herokuapp.com/'; 
const API_Local_URL = "http://localhost:3000"


const Quiz = () => {
  const [screen, setScreen] = useState("screen1");
  const [numberOfCurrentScreen, setNumberOfCurrentScreen] = useState(1);
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    phone: "",
    gender: "",
    healthProblems: [],
    otherConditions: "",
    allergies: [],
    otherAllergies: "",
    primaryGoal: null,
    otherPrimaryGoal: "",
    serviceGoal: "",
    meetingsPerMonth: null,
    achievements: ""
  });

  const handleInputChange = (field, value) => {
    setFormData(prevData => ({
      ...prevData,
      [field]: value
    }));
  };

  const changeScreen = (screen, number) => {
    setScreen(screen);
    setNumberOfCurrentScreen(number);
    window.scrollTo(0, 0);
  };

  const submitData = async () => {
    const data = {
      name: formData.name,
      email: formData.email,
      phone: formData.phone,
      gender: formData.gender,
      healthProblems: JSON.stringify(formData.healthProblems), // Convert array to string
      otherConditions: formData.otherConditions,
      allergies: JSON.stringify(formData.allergies), // Convert array to string
      otherAllergies: formData.otherAllergies,
      primaryGoal: formData.primaryGoal,
      otherPrimaryGoal: formData.otherPrimaryGoal,
      serviceGoal: formData.serviceGoal,
      meetingsPerMonth: formData.meetingsPerMonth,
      achievements: formData.achievements
    };
  
    const response = await fetch(`${API_BASE_URL}/quiz_customers`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(data),
    });
  
    const result = await response.json();
    console.log(result);
  };

  const totalScreens = 7; // total number of screens
  const progressPercentage = (numberOfCurrentScreen / totalScreens) * 100;

  return (
    <>
      <div className="progress-background">
        <div className="progress-container">
          <div className="progress-bar-background">
            <div className="progress-bar" style={{ width: `${progressPercentage}%` }}>
              {numberOfCurrentScreen} / {totalScreens}
            </div>
          </div>
        </div>
      </div>
      {screen === "screen1" && (
        <ScreenOne screen={changeScreen} nmscreen={numberOfCurrentScreen} />
      )}
      {screen === "screen2" && (
        <ScreenTwo
          screen={changeScreen}
          nmscreen={numberOfCurrentScreen}
          formData={formData}
          handleInputChange={handleInputChange}
        />
      )}
      {screen === "screen3" && (
        <ScreenThree
          screen={changeScreen}
          nmscreen={numberOfCurrentScreen}
          formData={formData}
          handleInputChange={handleInputChange}
        />
      )}
      {screen === "screen4" && (
        <ScreenFour
          screen={changeScreen}
          nmscreen={numberOfCurrentScreen}
          formData={formData}
          handleInputChange={handleInputChange}
        />
      )}
      {screen === "screen5" && (
        <ScreenFive
          screen={changeScreen}
          nmscreen={numberOfCurrentScreen}
          formData={formData}
          handleInputChange={handleInputChange}
        />
      )}
      {screen === "screen6" && (
        <ScreenSix
          screen={changeScreen}
          nmscreen={numberOfCurrentScreen}
          formData={formData}
          handleInputChange={handleInputChange}
          submitData={submitData}
        />
      )}
      {screen === "screen7" && (
        <ScreenSeven />
      )}
    </>
  );
};

export default Quiz;
